// The ensures of `det_set` is an implication `H ==> det_set_equal(...)`
// where H is the 4-conjunct
//   post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out)
//   && post1_self_.wf()
//   && post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out)
//   && post2_self_.wf().
// H is the antecedent of the postcondition, NOT a precondition, so we
// cannot unconditionally `assert` any of its conjuncts here — that was
// the previous attempt's mistake (lines 893-894 in the prior log).
//
// Instead, branch on H. Inside the branch all four facts hold, so we
// can chain post1_self_.seq@ =~= update =~= post2_self_.seq@ and then
// lift through Ghost extensionality to `post1_self_.seq == post2_self_.seq`.
// This gives z3 the explicit term-level equalities it needs to discharge
// the ensures implication; trigger gap on the two ensures (which have
// disjoint `seq@` instances on either side) is closed because both are
// rewritten via `=~=` to the common term `pre_self_.seq@.update(i as int, out)`.
seq_update_lemma::<A>();
if (post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
    && post1_self_.wf()
    && (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
    && post2_self_.wf()
{
    // Inside this proof branch, the four conjuncts of H are facts.
    // Transitivity through the common update term.
    assert(post1_self_.seq@ =~= post2_self_.seq@);
    // Promote extensional `=~=` to term-level `==` so triggers fire.
    assert(post1_self_.seq@ == post2_self_.seq@);
    // Ghost<Seq<A>> is extensional in its `@` view, so the wrapper field
    // is equal whenever the unwrapped sequences are equal.
    assert(post1_self_.seq == post2_self_.seq);
}
// `r1` and `r2` are both of type `()` — unit has a single inhabitant,
// so this is trivial but it pins the equality term in z3.
assert(r1 == r2);
